console.log("正在编辑博客类型，userId = "+userId);layui.use(["form","layer","util"],function(){let form=layui.form;let layer=layui.layer;let user;if(userId){$.ajax({url:"/user/"+userId,method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200&&a.data){user=a.data[0];form.val("form-user",{id:user.id,username:user.username,password:user.password,qq:user.qq,tel:user.tel,email:user.email});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(form-user-submit)",function(a){let user=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/user/"+userId,data:{id:user.id,username:user.username,password:user.password,qq:user.qq,tel:user.tel,email:user.email},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false});form.verify({username:function(b,a){let usernameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!usernameRex.test(b)){return"用户名只能为2-20个字符"}},password:function(b,a){let passwordRex=/^[\w\W\s\u4e00-\u9fcc]{6,32}$/;if(!passwordRex.test(b)){return"密码只能为6-32个字符"}}})}else{layer.msg("参数错误",{icon:2})}});